#[test]
fn cpython_memoryview_constructor_and_weakref_edges_stay_focused() {
    let getbuf_diff_name = "cpython_memoryview_getbuf_fail_diff_subset";
    let getbuf_subset_name = "cpython_memoryview_getbuf_fail_subset";
    let weakref_diff_name = "cpython_memoryview_weakref_live_diff_subset";
    let weakref_subset_name = "cpython_memoryview_weakref_live_subset";

    for (diff_name, subset_name) in [
        (getbuf_diff_name, getbuf_subset_name),
        (weakref_diff_name, weakref_subset_name),
    ] {
        assert!(
            CPYTHON_DIFF.contains(&format!("fn {diff_name}(")),
            "memoryview CPython diff evidence `{diff_name}` must exist"
        );
        assert!(
            CPYTHON_SUBSET.contains(&format!("fn {subset_name}(")),
            "memoryview runtime subset evidence `{subset_name}` must exist"
        );
        for document in [MANIFEST, CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
            assert!(
                document.contains(diff_name) && document.contains(subset_name),
                "memoryview docs must link `{diff_name}` to `{subset_name}`"
            );
        }
    }

    let getbuf_diff = extract_rust_test_body(CPYTHON_DIFF, getbuf_diff_name);
    let getbuf_subset = extract_rust_test_body(CPYTHON_SUBSET, getbuf_subset_name);
    for required in [
        "for value in [{}, [], object(), 42, 'abc']",
        "memoryview(value)",
        "error.__class__.__name__",
    ] {
        assert!(
            getbuf_diff.contains(required) && getbuf_subset.contains(required),
            "memoryview getbuf-fail evidence must cover `{required}`"
        );
    }
    assert!(
        getbuf_subset.contains("dict TypeError")
            && getbuf_subset.contains("list TypeError")
            && getbuf_subset.contains("object TypeError")
            && getbuf_subset.contains("int TypeError")
            && getbuf_subset.contains("str TypeError"),
        "memoryview getbuf-fail subset evidence must assert TypeError for non-buffer objects"
    );

    let weakref_diff = extract_rust_test_body(CPYTHON_DIFF, weakref_diff_name);
    let weakref_subset = extract_rust_test_body(CPYTHON_SUBSET, weakref_subset_name);
    for required in [
        "import weakref",
        "weakref.ref(m)",
        "weakref.ref(m, callback)",
        "weakref.ref(m, None)",
        "weakref.ReferenceType",
        "len(seen)",
    ] {
        assert!(
            weakref_diff.contains(required) && weakref_subset.contains(required),
            "memoryview weakref-live evidence must cover `{required}`"
        );
    }

    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION, MANIFEST] {
        let lower_document = document.to_ascii_lowercase();
        assert!(
            document.contains("live-reference"),
            "memoryview docs must keep the live weakref subset visible"
        );
        assert!(
            lower_document.contains("callback invocation")
                && lower_document.contains("weakref")
                && lower_document.contains("clearing"),
            "memoryview docs must keep weakref clearing/callback collection behavior out of the live subset"
        );
        assert!(
            document.contains("full buffer protocol"),
            "memoryview docs must keep full buffer protocol outside the supported subset"
        );
    }
}

#[test]
fn cpython_memoryview_methods_release_diff_covers_basic_methods_runtime_subset() {
    let diff_name = "cpython_memoryview_methods_release_diff_subset";
    let subset_name = "cpython_memoryview_basic_methods_and_release_subset";

    assert!(
        CPYTHON_DIFF.contains(&format!("fn {diff_name}(")),
        "memoryview method/release direct CPython diff evidence must exist"
    );
    assert!(
        CPYTHON_SUBSET.contains(&format!("fn {subset_name}(")),
        "memoryview basic method/release runtime subset evidence must exist"
    );

    for document in [MANIFEST, CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        assert!(
            document.contains(diff_name) && document.contains(subset_name),
            "memoryview method/release docs must link `{diff_name}` to `{subset_name}`"
        );
    }

    let start = CPYTHON_DIFF
        .find(&format!("fn {diff_name}("))
        .expect("memoryview method/release diff evidence must exist");
    let body = &CPYTHON_DIFF[start..];
    let end = body.find("\n#[test]").unwrap_or(body.len());
    let body = &body[..end];

    for required in [
        "m.tobytes()",
        "m.tobytes('C')",
        "m.tobytes(order='A')",
        "class Order(str):",
        "m.tobytes(Order('C'))",
        "m.tobytes(order=Order('A'))",
        "memoryview(b'abc').tobytes(Order('Z'))",
        "memoryview(b'abc').tobytes('bad')",
        "m.tolist()",
        "memoryview(b'abc').tolist(1)",
        "memoryview(b'abc').tolist(bad=True)",
        "m.toreadonly()",
        "memoryview(b'abc').toreadonly(1)",
        "memoryview(b'abc').toreadonly(bad=True)",
        "with m as cm",
        "memoryview(b'abc').__enter__(1)",
        "memoryview(b'abc').__enter__(bad=True)",
        "m.release()",
        "memoryview(b'abc').release(1)",
        "memoryview(b'abc').release(bad=True)",
        "memoryview(b'abc').__exit__(None, None, None, bad=True)",
        "m.__exit__(*args)",
        "memoryview(b'abc').__len__(1)",
        "memoryview(b'abc').__len__(bad=True)",
        "memoryview(b'abc').__getitem__()",
        "memoryview(b'abc').__getitem__(0, 1)",
        "memoryview(b'abc').__getitem__(key=0)",
        "memoryview(b'abc').__delitem__()",
        "memoryview(b'abc').__delitem__(0, 1)",
        "memoryview(b'abc').__delitem__(key=0)",
        "memoryview(bytearray(b'abc')).__setitem__()",
        "memoryview(bytearray(b'abc')).__setitem__(0)",
        "memoryview(bytearray(b'abc')).__setitem__(0, 97, 98)",
        "memoryview(bytearray(b'abc')).__setitem__(key=0, value=97)",
        "list(reversed(m))",
    ] {
        assert!(
            body.contains(required),
            "memoryview method/release diff evidence must contain `{required}`"
        );
    }
    assert!(
        CPYTHON_SUBSET.contains("order must be 'C', 'F' or 'A'"),
        "memoryview method/release subset evidence must contain tobytes order ValueError text"
    );
    assert!(
        CPYTHON_SUBSET.contains("tobytes() argument 'order' must be str or None"),
        "memoryview method/release subset evidence must contain tobytes order TypeError text"
    );
    assert!(
        CPYTHON_SUBSET.contains("tobytes() got an unexpected keyword argument 'bad'"),
        "memoryview method/release subset evidence must contain tobytes unexpected keyword text"
    );
    for required in [
        "memoryview.tolist() takes no arguments",
        "memoryview.toreadonly() takes no arguments",
        "memoryview.release() takes no arguments",
        "memoryview.tolist() takes no keyword arguments",
        "memoryview.toreadonly() takes no keyword arguments",
        "memoryview.release() takes no keyword arguments",
        "memoryview.__enter__() takes no arguments",
        "memoryview.__enter__() takes no keyword arguments",
        "memoryview.__exit__() takes no keyword arguments",
        "exit-args 4 None True",
        "expected 0 arguments, got 1",
        "wrapper __len__() takes no keyword arguments",
        "expected 1 argument, got 0",
        "expected 1 argument, got 2",
        "wrapper __getitem__() takes no keyword arguments",
        "wrapper __delitem__() takes no keyword arguments",
        "__setitem__ expected 2 arguments, got 0",
        "__setitem__ expected 2 arguments, got 1",
        "__setitem__ expected 2 arguments, got 3",
        "wrapper __setitem__() takes no keyword arguments",
    ] {
        assert!(
            CPYTHON_SUBSET.contains(required),
            "memoryview method/release subset evidence must contain `{required}`"
        );
    }
}

