fn cpython_type_metadata_delete_errors_has_cpython_evidence() {
    let subset_name = "cpython_type_metadata_delete_errors_subset";
    let diff_name = "cpython_type_metadata_delete_errors_diff_subset";
    let subset_body = extract_rust_test_body(CPYTHON_SUBSET, subset_name);
    let diff_body = extract_rust_test_body(CPYTHON_DIFF, diff_name);

    for required in [
        "A.__name__ = 'Renamed'",
        "A.__qualname__ = 'Qualified'",
        "A.__module__ = 42",
        "['__name__', '__qualname__', '__module__', '__doc__']",
        "delattr(A, name)",
        "error.args == (str(error),)",
        "custom-values",
        "default-values",
    ] {
        assert!(
            subset_body.contains(required) && diff_body.contains(required),
            "type metadata delete subset and diff evidence must cover `{required}`"
        );
    }

    for required in [
        "\"custom __name__ TypeError cannot delete '__name__' attribute of immutable type 'Renamed' True\"",
        "\"custom __qualname__ TypeError cannot delete '__qualname__' attribute of immutable type 'Renamed' True\"",
        "\"custom __module__ TypeError cannot delete '__module__' attribute of immutable type 'Renamed' True\"",
        "\"custom __doc__ TypeError cannot delete '__doc__' attribute of immutable type 'Renamed' True\"",
        "\"custom-values Renamed Qualified 42 doc\"",
        "\"default __name__ TypeError cannot delete '__name__' attribute of immutable type 'B' True\"",
        "\"default __qualname__ TypeError cannot delete '__qualname__' attribute of immutable type 'B' True\"",
        "\"default __module__ TypeError cannot delete '__module__' attribute of immutable type 'B' True\"",
        "\"default __doc__ TypeError cannot delete '__doc__' attribute of immutable type 'B' True\"",
        "\"default-values B B __main__ None\"",
    ] {
        assert!(
            subset_body.contains(required),
            "type metadata delete subset output must pin `{required}`"
        );
    }

    for required in [
        "fn class_metadata_delete_error(",
        "class_name_value(class_name, attrs)",
        "cannot delete '{name}' attribute of immutable type '{public_name}'",
        "matches!(name, \"__name__\" | \"__qualname__\" | \"__module__\" | \"__doc__\")",
        "return Err(class_metadata_delete_error(&class_name, &attrs, name));",
    ] {
        assert!(
            VM_SOURCE.contains(required),
            "VM class metadata delete implementation must contain `{required}`"
        );
    }

    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        for required in [
            subset_name,
            diff_name,
            "class metadata deletion TypeError",
            "`__name__`, `__qualname__`, `__module__`, and `__doc__`",
            "preserves reassigned metadata values",
        ] {
            assert!(
                document.contains(required),
                "type metadata delete docs must contain `{required}`"
            );
        }
    }
}

#[test]
fn cpython_type_repr_module_qualname_has_cpython_evidence() {
    let subset_name = "cpython_type_repr_module_qualname_subset";
    let diff_name = "cpython_type_repr_module_qualname_diff_subset";
    let subset_body = extract_rust_test_body(CPYTHON_SUBSET, subset_name);
    let diff_body = extract_rust_test_body(CPYTHON_DIFF, diff_name);

    for required in [
        "repr(A)",
        "str(A)",
        "setattr(cls, '__module__', 'pkg.mod')",
        "setattr(cls, '__module__', 'builtins')",
        "setattr(cls, '__module__', None)",
        "setattr(cls, '__module__', 42)",
        "setattr(cls, '__qualname__', 'Renamed.Nested')",
        "repr(Outer.Inner)",
        "repr(B.__mro__)",
        "B.__module__ = 'pkg'",
        "B.__qualname__ = 'Q.R'",
        "'__module__': ''",
    ] {
        assert!(
            subset_body.contains(required) && diff_body.contains(required),
            "type repr module/qualname subset and diff evidence must cover `{required}`"
        );
    }

    for required in [
        "\"default <class '__main__.A'> <class '__main__.A'> __main__ A\"",
        "\"custom-module <class 'pkg.mod.A'> <class 'pkg.mod.A'> pkg.mod A\"",
        "\"builtins-module <class 'A'> <class 'A'> builtins A\"",
        "\"none-module <class 'A'> <class 'A'> None A\"",
        "\"int-module <class 'A'> <class 'A'> 42 A\"",
        "\"custom-qualname <class '__main__.Renamed.Nested'> <class '__main__.Renamed.Nested'> __main__ Renamed.Nested\"",
        "\"nested <class '__main__.Outer.Inner'> Outer.Inner\"",
        "\"mro (<class '__main__.B'>, <class 'object'>) True True\"",
        "\"mro-mutated (<class 'pkg.Q.R'>, <class 'object'>)\"",
        "\"empty-module <class '.Q'>  Q\"",
    ] {
        assert!(
            subset_body.contains(required),
            "type repr module/qualname subset output must pin `{required}`"
        );
    }

    for required in [
        "const CLASS_QUALNAME_ATTR",
        "fn format_class_repr(",
        "attrs.get(CLASS_QUALNAME_ATTR)",
        "attrs.get(\"__module__\")",
        "module != \"builtins\"",
        "\"<class '__main__.{qualname}'>\"",
        "Value::Class { name, attrs, .. } => format_class_repr(name, attrs)",
    ] {
        assert!(
            VALUE_SOURCE.contains(required),
            "Value class repr implementation must contain `{required}`"
        );
    }

    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        for required in [
            subset_name,
            diff_name,
            "type `repr()`",
            "`str()` module-qualified class names",
            "`__mro__` tuple repr",
            "`builtins` and non-string `__module__`",
        ] {
            assert!(
                document.contains(required),
                "type repr module/qualname docs must contain `{required}`"
            );
        }
    }
}

