fn assert_sandbox_manifest_subset_evidence(
    module: &str,
    required_evidence: &[&str],
    excluded_terms: &[&str],
) {
    let row = sandbox_stdlib_rows()
        .into_iter()
        .find(|row| row.module == module)
        .unwrap_or_else(|| panic!("sandbox stdlib manifest must include {module}"));

    for required in required_evidence {
        assert!(
            row.supported_surface.contains(required),
            "{module} sandbox manifest must list runtime subset evidence `{required}`"
        );
        assert!(
            CPYTHON_COVERAGE.contains(required),
            "coverage document must describe {module} runtime subset evidence `{required}`"
        );
    }

    for excluded in excluded_terms {
        assert!(
            row.excluded_surface.contains(excluded),
            "{module} sandbox manifest must keep `{excluded}` outside the default surface"
        );
    }
}

#[test]
fn functools_sandbox_manifest_lists_public_subset_evidence() {
    assert_sandbox_manifest_subset_evidence(
        "functools",
        &[
            "cpython_functools_public_helpers_subset",
            "cpython_functools_module_doc_metadata_subset",
            "cpython_functools_all_exports_subset",
            "cpython_functools_partial_subset",
            "cpython_functools_placeholder_partial_subset",
            "cpython_functools_placeholder_type_constructor_subset",
            "cpython_functools_partial_instance_module_metadata_subset",
            "cpython_functools_partialmethod_subset",
            "cpython_functools_placeholder_partialmethod_subset",
            "cpython_functools_cmp_to_key_subset",
            "cpython_functools_update_wrapper_wraps_subset",
            "cpython_functools_total_ordering_subset",
            "cpython_functools_cache_subset",
            "cpython_functools_lru_cache_subset",
            "cpython_functools_lru_cache_exception_subset",
            "cpython_functools_lru_cache_keyword_order_subset",
            "cpython_functools_lru_cache_argument_shape_subset",
            "cpython_functools_cache_wrapper_methods_subset",
            "cpython_functools_cache_wrapper_module_metadata_subset",
            "cpython_functools_cached_property_subset",
            "cpython_functools_cached_property_module_metadata_subset",
            "cpython_functools_reduce_subset",
            "cpython_functools_reduce_initial_keyword_subset",
            "cpython_functools_singledispatch_subset",
            "cpython_functools_singledispatchmethod_subset",
        ],
        &[],
    );

    let row = sandbox_stdlib_rows()
        .into_iter()
        .find(|row| row.module == "functools")
        .expect("sandbox stdlib manifest must include functools");
    for evidence in [
        "cpython_functools_public_helpers_diff_subset",
        "cpython_functools_module_doc_metadata_diff_subset",
        "cpython_functools_all_exports_diff_subset",
        "cpython_functools_partial_diff_subset",
        "cpython_functools_placeholder_partial_diff_subset",
        "cpython_functools_placeholder_type_constructor_diff_subset",
        "cpython_functools_partial_instance_module_metadata_diff_subset",
        "cpython_functools_partialmethod_diff_subset",
        "cpython_functools_placeholder_partialmethod_diff_subset",
        "cpython_functools_cmp_to_key_diff_subset",
        "cpython_functools_update_wrapper_wraps_diff_subset",
        "cpython_functools_total_ordering_diff_subset",
        "cpython_functools_cache_diff_subset",
        "cpython_functools_lru_cache_diff_subset",
        "cpython_functools_lru_cache_exception_diff_subset",
        "cpython_functools_lru_cache_keyword_order_diff_subset",
        "cpython_functools_lru_cache_argument_shape_diff_subset",
        "cpython_functools_cache_wrapper_methods_diff_subset",
        "cpython_functools_cache_wrapper_module_metadata_diff_subset",
        "cpython_functools_cached_property_diff_subset",
        "cpython_functools_cached_property_module_metadata_diff_subset",
        "cpython_functools_reduce_diff_subset",
        "cpython_functools_reduce_initial_keyword_diff_subset",
        "cpython_functools_singledispatch_diff_subset",
        "cpython_functools_singledispatchmethod_diff_subset",
        "cpython_functools_singledispatch_union_diff_subset",
    ] {
        assert!(
            row.diff_evidence.contains(evidence),
            "functools sandbox manifest must cite CPython diff evidence `{evidence}`"
        );
    }

    let public_diff =
        extract_rust_test_body(CPYTHON_DIFF, "cpython_functools_public_helpers_diff_subset");
    let public_subset =
        extract_rust_test_body(CPYTHON_SUBSET, "cpython_functools_public_helpers_subset");
    for required in [
        "functools.__package__",
        "object.__getattribute__(functools, '__package__')",
        "'__package__' in dir(functools)",
        "functools.__dict__['__package__']",
    ] {
        assert!(
            public_diff.contains(required) && public_subset.contains(required),
            "functools public helper diff and subset evidence must cover `{required}`"
        );
    }
    for required in ["\"functools ''\"", "\"True ''\""] {
        assert!(
            public_subset.contains(required),
            "functools public helper subset output must pin `{required}`"
        );
    }
    let functools_start = STDLIB_SOURCE
        .find("\"functools\" => Ok(module_value(")
        .expect("stdlib.rs must define the functools module");
    let functools_end = functools_start
        + STDLIB_SOURCE[functools_start..]
            .find("\"itertools\" => Ok(module_value(")
            .expect("functools module registry must precede itertools");
    let functools_registry = &STDLIB_SOURCE[functools_start..functools_end];
    assert!(
        functools_registry.contains("(\"__package__\", Value::String(String::new()))"),
        "functools stdlib module registry must set CPython-compatible empty __package__ metadata"
    );
    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        for required in [
            "cpython_functools_public_helpers_subset",
            "cpython_functools_public_helpers_diff_subset",
            "functools module `__package__` metadata",
            "`functools.__package__`",
        ] {
            assert!(
                document.contains(required),
                "functools module package metadata docs must contain `{required}`"
            );
        }
    }
    let doc_metadata_diff = extract_rust_test_body(
        CPYTHON_DIFF,
        "cpython_functools_module_doc_metadata_diff_subset",
    );
    let doc_metadata_subset = extract_rust_test_body(
        CPYTHON_SUBSET,
        "cpython_functools_module_doc_metadata_subset",
    );
    for required in [
        "doc = functools.__doc__",
        "doc.splitlines()[0]",
        "'__doc__' in dir(functools)",
        "functools.__dict__['__doc__'] == doc",
        "object.__getattribute__(functools, '__doc__')",
    ] {
        assert!(
            doc_metadata_diff.contains(required) && doc_metadata_subset.contains(required),
            "functools module __doc__ diff and subset evidence must cover `{required}`"
        );
    }
    for required in [
        "const FUNCTOOLS_DOC",
        "functools.py - Tools for working with functions and callable objects",
        "\"__doc__\"",
        "FUNCTOOLS_DOC.to_string()",
    ] {
        assert!(
            STDLIB_SOURCE.contains(required),
            "functools module __doc__ implementation must contain `{required}`"
        );
    }
    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        for required in [
            "cpython_functools_module_doc_metadata_subset",
            "cpython_functools_module_doc_metadata_diff_subset",
            "functools module `__doc__` metadata",
            "`functools.__doc__`",
        ] {
            assert!(
                document.contains(required),
                "functools module __doc__ docs must contain `{required}`"
            );
        }
    }

    assert!(
        LANGUAGE_TESTS.contains("functools_sandbox_subset_keeps_export_surface_explicit")
            && LANGUAGE_TESTS.contains(
                "'__doc__', '__all__', '_CacheInfo', '_lru_cache_wrapper', '_make_key', '_unwrap_partial'"
            )
            && LANGUAGE_TESTS.contains("functools.__doc__.splitlines()[0]")
            && LANGUAGE_TESTS.contains("'Placeholder'")
            && LANGUAGE_TESTS.contains("dir(functools)"),
        "functools sandbox export test must guard module __all__ and CPython cache internals"
    );

    let all_exports_diff =
        extract_rust_test_body(CPYTHON_DIFF, "cpython_functools_all_exports_diff_subset");
    let all_exports_subset =
        extract_rust_test_body(CPYTHON_SUBSET, "cpython_functools_all_exports_subset");
    for required in [
        "hasattr(functools, 'Placeholder')",
        "skipping functools.__all__ diff",
    ] {
        assert!(
            all_exports_diff.contains(required),
            "functools __all__ diff evidence must cover `{required}`"
        );
    }
    for required in [
        "functools.__all__ == expected",
        "functools.__dict__['__all__'] == expected",
        "'__all__' in dir(functools)",
        "'Placeholder' in functools.__all__",
        "functools.__all__[-1]",
        "if not hasattr(functools, name)",
    ] {
        assert!(
            all_exports_diff.contains(required),
            "functools __all__ diff evidence must cover `{required}`"
        );
        assert!(
            all_exports_subset.contains(required),
            "functools __all__ subset evidence must cover `{required}`"
        );
    }
    for required in [
        "const FUNCTOOLS_ALL",
        "\"Placeholder\"",
        "\"__all__\"",
        "string_list_value(FUNCTOOLS_ALL)",
    ] {
        assert!(
            STDLIB_SOURCE.contains(required),
            "functools __all__ implementation must contain `{required}`"
        );
    }
    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        assert!(
            document.contains("cpython_functools_all_exports_subset")
                && document.contains("cpython_functools_all_exports_diff_subset")
                && document.contains("functools.__all__"),
            "functools __all__ evidence must be documented in coverage and migration notes"
        );
    }

    let partial_module_diff = CPYTHON_DIFF
        .split("fn cpython_functools_partial_instance_module_metadata_diff_subset()")
        .nth(1)
        .and_then(|tail| {
            tail.split("fn cpython_functools_reduce_diff_subset()")
                .next()
        })
        .expect("functools partial module metadata diff evidence must be extractable");
    for required in [
        "hasattr(partial(int), '__module__')",
        "skipping functools.partial instance module metadata diff",
        "p.__module__",
        "p.__module__ = 'custom'",
        "del p.__module__",
    ] {
        assert!(
            partial_module_diff.contains(required),
            "functools partial module metadata CPython diff evidence must cover `{required}`"
        );
    }

    let partial_diff =
        extract_rust_test_body(CPYTHON_DIFF, "cpython_functools_partial_diff_subset");
    let partial_subset = extract_rust_test_body(CPYTHON_SUBSET, "cpython_functools_partial_subset");
    for required in [
        "lambda: partial()",
        "lambda: partial(2)",
        "lambda: partial(2)()",
        "print(p2.func is capture, p2.args, p2.keywords)",
        "partial(partial(capture, 'base', a=1), 'tail', a=2, b=3)",
        "print(error.__class__.__name__, str(error))",
    ] {
        assert!(
            partial_diff.contains(required),
            "functools partial CPython diff evidence must cover `{required}`"
        );
        assert!(
            partial_subset.contains(required),
            "functools partial runtime subset evidence must cover `{required}`"
        );
    }
    for required in [
        "type 'partial' takes at least one argument",
        "the first argument must be callable",
    ] {
        assert!(
            partial_subset.contains(required),
            "functools partial runtime subset evidence must assert exact diagnostic `{required}`"
        );
    }

    let placeholder_diff = extract_rust_test_body(
        CPYTHON_DIFF,
        "cpython_functools_placeholder_partial_diff_subset",
    );
    let placeholder_subset = extract_rust_test_body(
        CPYTHON_SUBSET,
        "cpython_functools_placeholder_partial_subset",
    );
    for required in [
        "hasattr(functools, 'Placeholder')",
        "skipping functools.Placeholder diff",
    ] {
        assert!(
            placeholder_diff.contains(required),
            "functools Placeholder CPython diff evidence must cover `{required}`"
        );
    }
    for required in [
        "P = functools.Placeholder",
        "type(P).__name__",
        "type(P).__module__",
        "P is functools.Placeholder",
        "hash(P) == hash(functools.Placeholder)",
        "functools.partial(f, P, 2)",
        "functools.partial(q, 1).args",
        "functools.partial(f, a=P)",
        "missing positional arguments in 'partial' call",
        "Placeholder cannot be passed as a keyword argument",
    ] {
        assert!(
            placeholder_diff.contains(required),
            "functools Placeholder CPython diff evidence must cover `{required}`"
        );
        assert!(
            placeholder_subset.contains(required),
            "functools Placeholder runtime subset evidence must cover `{required}`"
        );
    }
    for required in [
        "Value::FunctoolsPlaceholder",
        "fn partial_constructor_args(",
        "fn partial_call_args(",
        "fn reject_functools_placeholder_keywords(",
        "\"functools._PlaceholderType\"",
        "\"TypeError: Placeholder cannot be passed as a keyword argument\"",
    ] {
        assert!(
            VM_SOURCE.contains(required) || STDLIB_SOURCE.contains(required),
            "functools Placeholder implementation must contain `{required}`"
        );
    }
    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        assert!(
            document.contains("cpython_functools_placeholder_partial_subset")
                && document.contains("cpython_functools_placeholder_partial_diff_subset")
                && document.contains("functools.Placeholder"),
            "functools Placeholder evidence must be documented in coverage and migration notes"
        );
    }

    let placeholder_type_diff = extract_rust_test_body(
        CPYTHON_DIFF,
        "cpython_functools_placeholder_type_constructor_diff_subset",
    );
    let placeholder_type_subset = extract_rust_test_body(
        CPYTHON_SUBSET,
        "cpython_functools_placeholder_type_constructor_subset",
    );
    for required in [
        "hasattr(functools, 'Placeholder')",
        "skipping functools.Placeholder type constructor diff",
    ] {
        assert!(
            placeholder_type_diff.contains(required),
            "functools Placeholder type constructor diff evidence must cover `{required}`"
        );
    }
    for required in [
        "T = type(P)",
        "T() is P",
        "isinstance(P, T)",
        "T.__name__",
        "T.__module__",
        "PlaceholderType takes no arguments",
    ] {
        assert!(
            placeholder_type_diff.contains(required),
            "functools Placeholder type constructor diff evidence must cover `{required}`"
        );
        assert!(
            placeholder_type_subset.contains(required),
            "functools Placeholder type constructor subset evidence must cover `{required}`"
        );
    }
    for required in [
        "fn call_functools_placeholder_type(",
        "Ok(Value::FunctoolsPlaceholder)",
        "\"TypeError: PlaceholderType takes no arguments\"",
        "name == \"functools._PlaceholderType\"",
    ] {
        assert!(
            VM_SOURCE.contains(required),
            "functools Placeholder type constructor implementation must contain `{required}`"
        );
    }
    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        assert!(
            document.contains("cpython_functools_placeholder_type_constructor_subset")
                && document.contains("cpython_functools_placeholder_type_constructor_diff_subset")
                && document.contains("Placeholder type constructor"),
            "functools Placeholder type constructor evidence must be documented in coverage and migration notes"
        );
    }

    let placeholder_partialmethod_diff = extract_rust_test_body(
        CPYTHON_DIFF,
        "cpython_functools_placeholder_partialmethod_diff_subset",
    );
    let placeholder_partialmethod_subset = extract_rust_test_body(
        CPYTHON_SUBSET,
        "cpython_functools_placeholder_partialmethod_subset",
    );
    for required in [
        "hasattr(functools, 'Placeholder')",
        "skipping functools.Placeholder partialmethod diff",
    ] {
        assert!(
            placeholder_partialmethod_diff.contains(required),
            "functools Placeholder partialmethod diff evidence must cover `{required}`"
        );
    }
    for required in [
        "functools.partialmethod(f, P, 2)",
        "functools.partialmethod(f, P, P, 3)",
        "functools.partialmethod(base, 1)",
        "functools.partialmethod(base, 1, 2)",
        "functools.partialmethod(functools.partial(f, P, 2), 5)",
        "C.pm(c, 1)",
        "C.__dict__[\"nested\"].args",
        "missing positional arguments in 'partial' call",
        "functools.partialmethod(C.f, a=P)",
        "Placeholder cannot be passed as a keyword argument",
    ] {
        assert!(
            placeholder_partialmethod_diff.contains(required),
            "functools Placeholder partialmethod diff evidence must cover `{required}`"
        );
        assert!(
            placeholder_partialmethod_subset.contains(required),
            "functools Placeholder partialmethod subset evidence must cover `{required}`"
        );
    }
    for required in [
        "fn call_partialmethod_callable(",
        "call_args.extend(partial_call_args(bound_args, args)?);",
        "reject_functools_placeholder_keywords(&keywords)?;",
        "let inner_args = partial_constructor_args(inner_args, args);",
    ] {
        assert!(
            VM_SOURCE.contains(required),
            "functools Placeholder partialmethod implementation must contain `{required}`"
        );
    }
    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        assert!(
            document.contains("cpython_functools_placeholder_partialmethod_subset")
                && document.contains("cpython_functools_placeholder_partialmethod_diff_subset")
                && document.contains("`partialmethod()` positional placeholder filling"),
            "functools Placeholder partialmethod evidence must be documented in coverage and migration notes"
        );
    }

    let cache_wrapper_methods_diff = extract_rust_test_body(
        CPYTHON_DIFF,
        "cpython_functools_cache_wrapper_methods_diff_subset",
    );
    let cache_wrapper_methods_subset = extract_rust_test_body(
        CPYTHON_SUBSET,
        "cpython_functools_cache_wrapper_methods_subset",
    );
    for required in [
        "_lru_cache_wrapper.cache_info() takes no arguments (1 given)",
        "_lru_cache_wrapper.cache_info() takes no keyword arguments",
        "_lru_cache_wrapper.cache_clear() takes no arguments (1 given)",
        "_lru_cache_wrapper.cache_clear() takes no keyword arguments",
        "Report cache statistics",
        "Clear the cache and cache statistics",
    ] {
        assert!(
            cache_wrapper_methods_diff.contains(required),
            "functools cache wrapper methods CPython diff evidence must cover `{required}`"
        );
        assert!(
            cache_wrapper_methods_subset.contains(required),
            "functools cache wrapper methods runtime subset evidence must cover `{required}`"
        );
    }

    let cache_diff = extract_rust_test_body(CPYTHON_DIFF, "cpython_functools_cache_diff_subset");
    let cache_subset = extract_rust_test_body(CPYTHON_SUBSET, "cpython_functools_cache_subset");
    for required in [
        "@lru_cache(maxsize=False)",
        "@lru_cache(maxsize=True)",
        "@lru_cache(maxsize=I(3))",
        "false_cached.cache_parameters()",
        "true_cached.cache_parameters()",
        "subclass_cached.cache_parameters()",
        "Report cache statistics",
        "Clear the cache and cache statistics",
    ] {
        assert!(
            cache_diff.contains(required),
            "functools cache CPython diff evidence must cover `{required}`"
        );
        assert!(
            cache_subset.contains(required),
            "functools cache runtime subset evidence must cover `{required}`"
        );
    }

    let lru_argument_shape_diff = extract_rust_test_body(
        CPYTHON_DIFF,
        "cpython_functools_lru_cache_argument_shape_diff_subset",
    );
    let lru_argument_shape_subset = extract_rust_test_body(
        CPYTHON_SUBSET,
        "cpython_functools_lru_cache_argument_shape_subset",
    );
    for required in [
        "def identify(value):",
        "identify(1), identify(True), identify(1.0)",
        "def identify_kw(**kwargs):",
        "identify_kw(value=1), identify_kw(value=True), identify_kw(value=1.0)",
    ] {
        assert!(
            lru_argument_shape_diff.contains(required),
            "functools lru_cache CPython diff evidence must cover `{required}`"
        );
        assert!(
            lru_argument_shape_subset.contains(required),
            "functools lru_cache runtime subset evidence must cover `{required}`"
        );
    }

    let reduce_diff = extract_rust_test_body(CPYTHON_DIFF, "cpython_functools_reduce_diff_subset");
    for required in [
        "reduce(add, [0, 1], initial='')",
        "reduce(function=lambda x, y: (x or 1) + y, sequence=[1, 2, 3])",
        "reduce(lambda x, y: x + y, sequence=[1, 2, 3], initial=1)",
        "reduce(add, [1], 2, initial=3)",
        "reduce(add, None)",
        "reduce(add, BadIterReturn())",
        "reduce() takes at least 2 positional arguments (0 given)",
        "reduce() takes at least 2 positional arguments (1 given)",
        "reduce() takes at most 3 arguments (4 given)",
    ] {
        assert!(
            reduce_diff.contains(required),
            "functools reduce CPython diff evidence must cover `{required}`"
        );
    }

    let reduce_initial_diff = extract_rust_test_body(
        CPYTHON_DIFF,
        "cpython_functools_reduce_initial_keyword_diff_subset",
    );
    for required in [
        "reduce(add, [1, 2], initial=10)",
        "reduce(add, [], initial=42)",
        "CPython oracle lacks reduce(initial=...)",
        "reduce(add, [1], 2, initial=3)",
        "kw-function-sequence",
        "kw-sequence-with-function",
        "kw-foo-empty",
        "kw-foo-with-pos",
        "kw-function-with-pos",
        "kw-sequence-with-pos",
        "kw-initial-duplicate",
        "kw-four-initial",
        "reduce() takes at least 2 positional arguments (0 given)",
        "reduce() takes at least 2 positional arguments (1 given)",
        "reduce() got an unexpected keyword argument 'foo'",
        "reduce() got an unexpected keyword argument 'function'",
        "reduce() got an unexpected keyword argument 'sequence'",
    ] {
        assert!(
            reduce_initial_diff.contains(required),
            "functools reduce initial-keyword gated diff evidence must cover `{required}`"
        );
    }

    for excluded in [
        "Full CPython cache implementation internals",
        "weakref/lifecycle subtleties",
        "unsupported descriptor edge cases",
    ] {
        assert!(
            row.excluded_surface.contains(excluded),
            "functools sandbox manifest must keep unsupported boundary `{excluded}` documented"
        );
    }

    for required in [
        "Full CPython cache implementation internals",
        "weakref/lifecycle subtleties",
        "unsupported descriptor edge cases",
    ] {
        assert!(
            CPYTHON_MIGRATION.contains(required),
            "functools migration notes must document sandbox boundary `{required}`"
        );
        assert!(
            CPYTHON_COVERAGE.contains(required),
            "functools coverage notes must document sandbox boundary `{required}`"
        );
    }

    for required in [
        "newer-oracle",
        "missing-positional diagnostics",
        "unsupported-keyword text",
    ] {
        assert!(
            CPYTHON_COVERAGE.contains(required),
            "functools coverage notes must document reduce keyword boundary `{required}`"
        );
    }
    for required in [
        "newer-CPython",
        "positional-only `function` / `sequence` keyword forms",
        "unsupported keyword forms",
    ] {
        assert!(
            CPYTHON_MIGRATION.contains(required),
            "functools migration notes must document reduce keyword boundary `{required}`"
        );
    }
}

#[test]
fn functools_descriptor_helpers_diff_cover_runtime_subsets() {
    for (subset, diff) in [
        (
            "cpython_functools_partialmethod_subset",
            "cpython_functools_partialmethod_diff_subset",
        ),
        (
            "cpython_functools_cached_property_subset",
            "cpython_functools_cached_property_diff_subset",
        ),
        (
            "cpython_functools_singledispatchmethod_subset",
            "cpython_functools_singledispatchmethod_diff_subset",
        ),
    ] {
        assert!(
            CPYTHON_SUBSET.contains(subset),
            "functools descriptor runtime subset evidence `{subset}` must exist"
        );
        assert!(
            CPYTHON_DIFF.contains(diff),
            "functools descriptor CPython diff evidence `{diff}` must exist"
        );
        assert!(
            CPYTHON_COVERAGE.contains(subset) && CPYTHON_COVERAGE.contains(diff),
            "coverage document must link functools descriptor evidence `{subset}` / `{diff}`"
        );
        assert!(
            CPYTHON_MIGRATION.contains(subset),
            "migration document must describe functools descriptor subset `{subset}`"
        );
    }

    let partialmethod_diff = CPYTHON_DIFF
        .split("fn cpython_functools_partialmethod_diff_subset()")
        .nth(1)
        .and_then(|tail| {
            tail.split("fn cpython_functools_cached_property_diff_subset()")
                .next()
        })
        .expect("functools partialmethod diff evidence must be extractable");
    for required in [
        "partialmethod(staticmethod(capture), 8)",
        "partialmethod(classmethod(capture), d=9)",
        "A.both(a, 5, c=6)",
        "hasattr(a.both, '__self__')",
        "descriptor.__get__(obj=a, cls=A)",
        "partialmethod.__get__() missing 1 required positional argument: 'obj'",
        "partialmethod.__get__() got multiple values for argument 'obj'",
        "state = descriptor_state.__dict__",
        "descriptor_state.func = 'custom-func'",
        "del descriptor_state.func",
        "rendered.endswith(', , )')",
        "rendered.endswith(', 7, )')",
    ] {
        assert!(
            partialmethod_diff.contains(required),
            "partialmethod diff evidence must cover descriptor binding detail `{required}`"
        );
    }

    let cached_property_diff = CPYTHON_DIFF
        .split("fn cpython_functools_cached_property_diff_subset()")
        .nth(1)
        .and_then(|tail| {
            tail.split("fn cpython_functools_cache_diff_subset()")
                .next()
        })
        .expect("functools cached_property diff evidence must be extractable");
    let cached_property_subset =
        extract_rust_test_body(CPYTHON_SUBSET, "cpython_functools_cached_property_subset");
    for required in [
        "CachedCostItem.cost.__doc__",
        "CachedCostItem.__dict__['cost'].__dict__",
        "Dynamic = type('Dynamic', (), {'field': DynamicDescriptor()})",
        "def __set_name__(self, owner, name):",
        "cached_property()",
        "cached_property.__init__() missing 1 required positional argument: 'func'",
        "descriptor.__get__(instance=CachedCostItem())",
        "cached_property.__get__() missing 1 required positional argument: 'instance'",
        "cached_property.__get__() got multiple values for argument 'instance'",
        "cached_property.__set_name__() missing 2 required positional arguments: 'owner' and 'name'",
        "cached_property.__set_name__() got multiple values for argument 'owner'",
        "Cannot assign the same cached_property to two different names ('a' and 'b').",
    ] {
        assert!(
            cached_property_diff.contains(required),
            "cached_property diff evidence must cover descriptor detail `{required}`"
        );
        assert!(
            cached_property_subset.contains(required),
            "cached_property runtime subset evidence must cover descriptor detail `{required}`"
        );
    }

    let cached_property_module_diff = CPYTHON_DIFF
        .split("fn cpython_functools_cached_property_module_metadata_diff_subset()")
        .nth(1)
        .and_then(|tail| {
            tail.split("fn cpython_functools_cache_diff_subset()")
                .next()
        })
        .expect("functools cached_property module metadata diff evidence must be extractable");
    for required in [
        "skipping functools.cached_property module metadata diff",
        "descriptor.__module__",
        "descriptor.__module__ = 'custom'",
        "del descriptor.__module__",
    ] {
        assert!(
            cached_property_module_diff.contains(required),
            "cached_property module metadata diff evidence must cover descriptor detail `{required}`"
        );
    }

    let cache_wrapper_module_diff = CPYTHON_DIFF
        .split("fn cpython_functools_cache_wrapper_module_metadata_diff_subset()")
        .nth(1)
        .and_then(|tail| {
            tail.split("fn cpython_functools_singledispatch_diff_subset()")
                .next()
        })
        .expect("functools cache wrapper module metadata diff evidence must be extractable");
    for required in [
        "skipping functools cache wrapper module metadata diff",
        "wrapper.__module__",
        "wrapper.__module__ = 'custom'",
        "del wrapper.__module__",
    ] {
        assert!(
            cache_wrapper_module_diff.contains(required),
            "cache wrapper module metadata diff evidence must cover detail `{required}`"
        );
    }

    let singledispatch_diff = CPYTHON_DIFF
        .split("fn cpython_functools_singledispatch_diff_subset()")
        .nth(1)
        .and_then(|tail| {
            tail.split("fn cpython_functools_singledispatchmethod_diff_subset()")
                .next()
        })
        .expect("functools singledispatch diff evidence must be extractable");
    for required in [
        "h.__dict__['registry']",
        "h.__dict__[name] is getattr(h, name)",
        "shadow.register = 'shadowed'",
        "del shadow.register",
    ] {
        assert!(
            singledispatch_diff.contains(required),
            "singledispatch diff evidence must cover wrapper __dict__ detail `{required}`"
        );
    }

    let singledispatchmethod_diff = CPYTHON_DIFF
        .split("fn cpython_functools_singledispatchmethod_diff_subset()")
        .nth(1)
        .and_then(|tail| {
            tail.split("fn assert_cpython_itertools_core_iterator_diff")
                .next()
        })
        .expect("functools singledispatchmethod diff evidence must be extractable");
    for required in [
        "descriptor = C.__dict__['m']",
        "descriptor.func.__name__",
        "descriptor.__module__",
        "descriptor.__module__ = 'custom'",
        "del descriptor.__module__",
        "descriptor.__get__(obj=c, cls=C)",
        "<single dispatch method descriptor C.m>",
        "<bound single dispatch method C.m of ",
        "<single dispatch method C.m>",
        "singledispatchmethod.__get__() missing 1 required positional argument: 'obj'",
        "singledispatchmethod.__get__() got multiple values for argument 'obj'",
        "@staticmethod",
        "@classmethod",
        "@c.m.register(bytes)",
    ] {
        assert!(
            singledispatchmethod_diff.contains(required),
            "singledispatchmethod diff evidence must cover descriptor detail `{required}`"
        );
    }

    let union_diff = extract_rust_test_body(
        CPYTHON_DIFF,
        "cpython_functools_singledispatch_union_diff_subset",
    );
    for required in [
        "skipping functools singledispatch union diff",
        "def _(obj: int | str):",
        "from typing import Union",
        "def _(obj: Union[str, bytes]):",
        "def _(obj: float | complex):",
        "g.register(tuple | list, pair)",
        "descriptor.register(tuple | list, method_pair)",
    ] {
        assert!(
            union_diff.contains(required),
            "functools singledispatch union gated diff evidence must cover `{required}`"
        );
    }
}

#[test]
fn itertools_sandbox_manifest_lists_public_subset_evidence() {
    assert_sandbox_manifest_subset_evidence(
        "itertools",
        &[
            "cpython_itertools_core_iterator_subset",
            "cpython_itertools_module_doc_metadata_subset",
            "cpython_itertools_chain_subset",
            "cpython_itertools_chain_from_iterable_subset",
            "cpython_itertools_repeat_subset",
            "cpython_itertools_cycle_subset",
            "cpython_itertools_compress_subset",
            "cpython_itertools_filterfalse_subset",
            "cpython_itertools_takewhile_subset",
            "cpython_itertools_dropwhile_subset",
            "cpython_itertools_starmap_subset",
            "cpython_itertools_accumulate_subset",
            "cpython_itertools_zip_longest_subset",
            "cpython_itertools_islice_subset",
            "cpython_itertools_islice_error_subset",
            "cpython_itertools_count_subset",
            "cpython_itertools_count_error_subset",
            "cpython_itertools_count_bool_arithmetic_subset",
            "cpython_itertools_keyword_error_subset",
            "cpython_itertools_pairwise_subset",
            "cpython_itertools_product_subset",
            "cpython_itertools_combinations_subset",
            "cpython_itertools_combinations_with_replacement_subset",
            "cpython_itertools_permutations_subset",
            "cpython_itertools_tee_subset",
            "cpython_itertools_batched_subset",
            "cpython_itertools_groupby_subset",
            "cpython_itertools_repr_subset",
        ],
        &[],
    );

    let row = sandbox_stdlib_rows()
        .into_iter()
        .find(|row| row.module == "itertools")
        .expect("sandbox stdlib manifest must include itertools");
    for evidence in [
        "cpython_itertools_core_diff_subset",
        "cpython_itertools_core_iterator_diff_subset",
        "cpython_itertools_module_doc_metadata_diff_subset",
        "cpython_itertools_chain_diff_subset",
        "cpython_itertools_chain_from_iterable_diff_subset",
        "cpython_itertools_repeat_diff_subset",
        "cpython_itertools_cycle_diff_subset",
        "cpython_itertools_compress_diff_subset",
        "cpython_itertools_filterfalse_diff_subset",
        "cpython_itertools_takewhile_diff_subset",
        "cpython_itertools_dropwhile_diff_subset",
        "cpython_itertools_starmap_diff_subset",
        "cpython_itertools_accumulate_diff_subset",
        "cpython_itertools_zip_longest_diff_subset",
        "cpython_itertools_islice_diff_subset",
        "cpython_itertools_islice_error_diff_subset",
        "cpython_itertools_count_diff_subset",
        "cpython_itertools_count_error_diff_subset",
        "cpython_itertools_count_bool_arithmetic_diff_subset",
        "cpython_itertools_keyword_error_diff_subset",
        "cpython_itertools_pairwise_diff_subset",
        "cpython_itertools_product_diff_subset",
        "cpython_itertools_combinations_diff_subset",
        "cpython_itertools_combinations_with_replacement_diff_subset",
        "cpython_itertools_permutations_diff_subset",
        "cpython_itertools_tee_diff_subset",
        "cpython_itertools_batched_diff_subset",
        "cpython_itertools_groupby_diff_subset",
        "cpython_itertools_repr_diff_subset",
    ] {
        assert!(
            row.diff_evidence.contains(evidence),
            "itertools sandbox manifest must cite CPython diff evidence `{evidence}`"
        );
    }

    let core_diff =
        extract_rust_test_body(CPYTHON_DIFF, "assert_cpython_itertools_core_iterator_diff");
    let core_subset =
        extract_rust_test_body(CPYTHON_SUBSET, "cpython_itertools_core_iterator_subset");
    for required in [
        "itertools.__package__",
        "object.__getattribute__(itertools, '__package__')",
        "'__package__' in dir(itertools)",
        "itertools.__dict__['__package__']",
    ] {
        assert!(
            core_diff.contains(required) && core_subset.contains(required),
            "itertools core diff and subset evidence must cover `{required}`"
        );
    }
    for required in ["\"itertools ''\"", "\"True ''\""] {
        assert!(
            core_subset.contains(required),
            "itertools core subset output must pin `{required}`"
        );
    }
    let itertools_start = STDLIB_SOURCE
        .find("\"itertools\" => Ok(module_value(")
        .expect("stdlib.rs must define the itertools module");
    let itertools_end = itertools_start
        + STDLIB_SOURCE[itertools_start..]
            .find("\"operator\" => Ok(operator_module_value())")
            .expect("itertools module registry must precede operator");
    let itertools_registry = &STDLIB_SOURCE[itertools_start..itertools_end];
    assert!(
        itertools_registry.contains("(\"__package__\", Value::String(String::new()))"),
        "itertools stdlib module registry must set CPython-compatible empty __package__ metadata"
    );
    assert!(
        itertools_registry.contains("(\"__doc__\", Value::String(ITERTOOLS_DOC.to_string()))")
            && STDLIB_SOURCE.contains("const ITERTOOLS_DOC")
            && STDLIB_SOURCE.contains("Functional tools for creating and using iterators."),
        "itertools stdlib module registry must set CPython-compatible __doc__ metadata"
    );
    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        for required in [
            "cpython_itertools_core_iterator_subset",
            "cpython_itertools_core_diff_subset",
            "itertools module `__package__` metadata",
            "`itertools.__package__`",
        ] {
            assert!(
                document.contains(required),
                "itertools module package metadata docs must contain `{required}`"
            );
        }
    }
    let itertools_doc_diff = extract_rust_test_body(
        CPYTHON_DIFF,
        "cpython_itertools_module_doc_metadata_diff_subset",
    );
    let itertools_doc_subset = extract_rust_test_body(
        CPYTHON_SUBSET,
        "cpython_itertools_module_doc_metadata_subset",
    );
    for required in [
        "doc = itertools.__doc__",
        "doc.splitlines()[0]",
        "len(doc)",
        "'__doc__' in dir(itertools)",
        "itertools.__dict__['__doc__'] == doc",
        "object.__getattribute__(itertools, '__doc__')",
    ] {
        assert!(
            itertools_doc_diff.contains(required) && itertools_doc_subset.contains(required),
            "itertools module __doc__ diff and subset evidence must cover `{required}`"
        );
    }
    assert!(
        itertools_doc_diff.contains("repr(object.__getattribute__(itertools, '__doc__'))"),
        "itertools module __doc__ diff evidence must compare full CPython repr"
    );
    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        for required in [
            "cpython_itertools_module_doc_metadata_subset",
            "cpython_itertools_module_doc_metadata_diff_subset",
            "itertools module `__doc__` metadata",
            "`itertools.__doc__`",
        ] {
            assert!(
                document.contains(required),
                "itertools module __doc__ docs must contain `{required}`"
            );
        }
    }

    assert!(
        LANGUAGE_TESTS.contains("itertools_sandbox_subset_keeps_export_surface_explicit")
            && LANGUAGE_TESTS.contains("itertools.__doc__.splitlines()[0]")
            && LANGUAGE_TESTS.contains("'__all__', 'imap', 'izip', 'ifilter', 'ifilterfalse'")
            && LANGUAGE_TESTS.contains("dir(itertools)"),
        "itertools sandbox export test must guard module __doc__, module __all__, and non-subset aliases"
    );

    for required in [
        "repeat() missing required argument 'object' (pos 1)",
        "repeat() takes at most 2 arguments (3 given)",
    ] {
        assert!(
            CPYTHON_SUBSET.contains(required) && CPYTHON_DIFF.contains(required),
            "itertools repeat CPython parity must guard `{required}` in subset and diff evidence"
        );
    }

    for required in [
        "chain.from_iterable() takes exactly one argument (0 given)",
        "chain.from_iterable() takes exactly one argument (2 given)",
    ] {
        assert!(
            CPYTHON_SUBSET.contains(required) && CPYTHON_DIFF.contains(required),
            "itertools chain.from_iterable CPython parity must guard `{required}` in subset and diff evidence"
        );
    }

    for required in [
        "islice expected at least 2 arguments, got 1",
        "islice expected at most 4 arguments, got 5",
    ] {
        assert!(
            CPYTHON_SUBSET.contains(required) && CPYTHON_DIFF.contains(required),
            "itertools islice CPython parity must guard `{required}` in subset and diff evidence"
        );
    }

    for required in [
        "itertools.count(0, 1, 2)",
        "count() takes at most 2 arguments (3 given)",
    ] {
        assert!(
            CPYTHON_SUBSET.contains(required) && CPYTHON_DIFF.contains(required),
            "itertools count CPython parity must guard `{required}` in subset and diff evidence"
        );
    }

    for excluded in [
        "Full itertools module",
        "pickling exactness",
        "exact address repr",
        "`tee()` cache compaction",
        "remaining public/helper types",
    ] {
        assert!(
            row.excluded_surface.contains(excluded),
            "itertools sandbox manifest must keep unsupported boundary `{excluded}` documented"
        );
    }

    for required in [
        "without exact address binding",
        "public iterator/helper type `__module__` / `__qualname__` / `__doc__` metadata",
        "`_grouper.__doc__ is None`",
        "Full itertools module",
        "pickling exactness",
        "exact address repr",
        "`tee()` cache compaction",
        "remaining public/helper types",
    ] {
        assert!(
            CPYTHON_MIGRATION.contains(required),
            "itertools migration notes must document sandbox boundary `{required}`"
        );
    }

    for required in [
        "without binding object addresses",
        "public iterator/helper\n  type `__module__` / `__qualname__` / `__doc__` metadata",
        "`_grouper.__doc__ is None`",
        "`tee()` cache compaction",
        "pickling exactness",
        "remaining public/helper",
    ] {
        assert!(
            CPYTHON_COVERAGE.contains(required),
            "itertools coverage notes must document sandbox boundary `{required}`"
        );
    }
}

#[test]
fn itertools_core_and_pairwise_runtime_evidence_stay_split() {
    let core_start = CPYTHON_SUBSET
        .find("fn cpython_itertools_core_iterator_subset()")
        .expect("itertools core runtime subset evidence must exist");
    let keyword_start = CPYTHON_SUBSET
        .find("fn cpython_itertools_keyword_error_subset()")
        .expect("itertools keyword error runtime subset evidence must exist");
    let count_bool_start = CPYTHON_SUBSET
        .find("fn cpython_itertools_count_bool_arithmetic_subset()")
        .expect("itertools count bool arithmetic runtime subset evidence must exist");
    let pairwise_start = CPYTHON_SUBSET
        .find("fn cpython_itertools_pairwise_subset()")
        .expect("itertools pairwise runtime subset evidence must exist");
    let product_start = CPYTHON_SUBSET
        .find("fn cpython_itertools_product_subset()")
        .expect("itertools product runtime subset evidence must exist");
    let combinations_start = CPYTHON_SUBSET
        .find("fn cpython_itertools_combinations_subset()")
        .expect("itertools combinations runtime subset evidence must exist");
    let replacement_start = CPYTHON_SUBSET
        .find("fn cpython_itertools_combinations_with_replacement_subset()")
        .expect("itertools combinations_with_replacement runtime subset evidence must exist");
    let permutations_start = CPYTHON_SUBSET
        .find("fn cpython_itertools_permutations_subset()")
        .expect("itertools permutations runtime subset evidence must exist");
    let tee_start = CPYTHON_SUBSET
        .find("fn cpython_itertools_tee_subset()")
        .expect("itertools tee runtime subset evidence must exist");
    let batched_start = CPYTHON_SUBSET
        .find("fn cpython_itertools_batched_subset()")
        .expect("itertools batched runtime subset evidence must exist");
    let groupby_start = CPYTHON_SUBSET
        .find("fn cpython_itertools_groupby_subset()")
        .expect("itertools groupby runtime subset evidence must exist");
    let groupby_end = CPYTHON_SUBSET[groupby_start..]
        .find("\n// Adapted from CPython Lib/test/test_list.py")
        .map(|offset| groupby_start + offset)
        .expect("itertools groupby subset must end before sequence constructor tests");

    let core_source = &CPYTHON_SUBSET[core_start..count_bool_start];
    let count_bool_source = &CPYTHON_SUBSET[count_bool_start..keyword_start];
    let keyword_source = &CPYTHON_SUBSET[keyword_start..pairwise_start];
    let pairwise_source = &CPYTHON_SUBSET[pairwise_start..product_start];
    let product_source = &CPYTHON_SUBSET[product_start..combinations_start];
    let combinations_source = &CPYTHON_SUBSET[combinations_start..replacement_start];
    let replacement_source = &CPYTHON_SUBSET[replacement_start..permutations_start];
    let permutations_source = &CPYTHON_SUBSET[permutations_start..tee_start];
    let tee_source = &CPYTHON_SUBSET[tee_start..batched_start];
    let batched_source = &CPYTHON_SUBSET[batched_start..groupby_start];
    let groupby_source = &CPYTHON_SUBSET[groupby_start..groupby_end];

    assert!(
        !core_source.contains("pairwise"),
        "itertools core runtime evidence must not cover pairwise()"
    );
    assert!(
        core_source.contains("itertools.accumulate([1, 2], initial=None)")
            && core_source.contains("\"[1, 3]\""),
        "itertools core runtime evidence must assert accumulate(initial=None) omission"
    );
    assert!(
        core_source.contains("itertools.islice(range(3), None)"),
        "itertools core runtime evidence must assert islice(stop=None) two-argument behavior"
    );
    assert!(
        core_source.contains("class BadIndex:")
            && core_source.contains("itertools.islice(range(5), BadIndex())")
            && core_source.contains("Indices for islice() must be None or an integer")
            && core_source.contains("Step for islice() must be a positive integer or None."),
        "itertools core runtime evidence must assert islice bad __index__ error classification"
    );
    for required in [
        "(True, False) [True, 1, 1, 1, 1]",
        "(True, True) [1, 2, 3, 4, 5]",
        "(False, True) [0, 1, 2, 3, 4]",
        "(False, False) [False, 0, 0, 0, 0]",
        "(True, 2) [True, 3, 5, 7, 9]",
        "(1, True) [1, 2, 3, 4, 5]",
    ] {
        assert!(
            count_bool_source.contains(required),
            "itertools count bool arithmetic runtime evidence must assert `{required}`"
        );
    }
    assert!(
        keyword_source.contains("multiple values"),
        "itertools keyword-error runtime evidence must assert duplicate keyword diagnostics"
    );
    for required in [
        "itertools.compress()",
        "itertools.compress([1])",
        "itertools.compress([1], data=[])",
        "count() got an unexpected keyword argument 'foo'",
        "repeat() got an unexpected keyword argument 'bad'",
        "compress() missing required argument 'data' (pos 1)",
        "compress() missing required argument 'selectors' (pos 2)",
        "itertools.groupby()",
        "itertools.groupby([1], iterable=[])",
        "groupby() missing required argument 'iterable' (pos 1)",
        "itertools.combinations()",
        "itertools.combinations([1])",
        "combinations() missing required argument 'r' (pos 2)",
        "itertools.combinations_with_replacement()",
        "combinations_with_replacement() missing required argument 'r' (pos 2)",
        "itertools.permutations()",
        "permutations() missing required argument 'iterable' (pos 1)",
    ] {
        assert!(
            keyword_source.contains(required),
            "itertools keyword-error runtime evidence must cover `{required}`"
        );
    }
    assert!(
        pairwise_source.contains("itertools.pairwise"),
        "itertools pairwise runtime evidence must cover pairwise()"
    );
    assert!(
        product_source.contains("itertools.product"),
        "itertools product runtime evidence must cover product()"
    );
    assert!(
        combinations_source.contains("itertools.combinations"),
        "itertools combinations runtime evidence must cover combinations()"
    );
    assert!(
        replacement_source.contains("itertools.combinations_with_replacement"),
        "itertools combinations_with_replacement runtime evidence must cover combinations_with_replacement()"
    );
    assert!(
        permutations_source.contains("itertools.permutations")
            && permutations_source.contains("itertools.permutations([1, 2], None)"),
        "itertools permutations runtime evidence must cover permutations() including r=None"
    );
    assert!(
        tee_source.contains("itertools.tee"),
        "itertools tee runtime evidence must cover tee()"
    );
    for required in [
        "c, d = itertools.tee(a)",
        "print(c is a, d is a, c is d)",
        "False False False",
        "3 3 [3, 4] [4] [4] [2, 3, 4]",
    ] {
        assert!(
            tee_source.contains(required),
            "itertools tee runtime evidence must cover tee-of-tee flattening `{required}`"
        );
    }
    assert!(
        batched_source.contains("itertools.batched"),
        "itertools batched runtime evidence must cover batched()"
    );
    assert!(
        groupby_source.contains("itertools.groupby"),
        "itertools groupby runtime evidence must cover groupby()"
    );
}

#[test]
fn itertools_core_and_pairwise_diff_evidence_stay_split() {
    let core_helper_start = CPYTHON_DIFF
        .find("fn assert_cpython_itertools_core_iterator_diff")
        .expect("itertools core iterator diff helper evidence must exist");
    let core_start = CPYTHON_DIFF
        .find("fn cpython_itertools_core_diff_subset()")
        .expect("itertools core diff evidence must exist");
    let pairwise_start = CPYTHON_DIFF
        .find("fn cpython_itertools_pairwise_diff_subset()")
        .expect("itertools pairwise diff evidence must exist");
    let keyword_start = CPYTHON_DIFF
        .find("fn cpython_itertools_keyword_error_diff_subset()")
        .expect("itertools keyword-error diff evidence must exist");
    let count_bool_start = CPYTHON_DIFF
        .find("fn cpython_itertools_count_bool_arithmetic_diff_subset()")
        .expect("itertools count bool arithmetic diff evidence must exist");
    let product_start = CPYTHON_DIFF
        .find("fn cpython_itertools_product_diff_subset()")
        .expect("itertools product diff evidence must exist");
    let combinations_start = CPYTHON_DIFF
        .find("fn cpython_itertools_combinations_diff_subset()")
        .expect("itertools combinations diff evidence must exist");
    let replacement_start = CPYTHON_DIFF
        .find("fn cpython_itertools_combinations_with_replacement_diff_subset()")
        .expect("itertools combinations_with_replacement diff evidence must exist");
    let permutations_start = CPYTHON_DIFF
        .find("fn cpython_itertools_permutations_diff_subset()")
        .expect("itertools permutations diff evidence must exist");
    let tee_start = CPYTHON_DIFF
        .find("fn cpython_itertools_tee_diff_subset()")
        .expect("itertools tee diff evidence must exist");
    let batched_start = CPYTHON_DIFF
        .find("fn cpython_itertools_batched_diff_subset()")
        .expect("itertools batched diff evidence must exist");
    let groupby_start = CPYTHON_DIFF
        .find("fn cpython_itertools_groupby_diff_subset()")
        .expect("itertools groupby diff evidence must exist");
    let repr_start = CPYTHON_DIFF
        .find("fn cpython_itertools_repr_diff_subset()")
        .expect("itertools repr diff evidence must exist");
    let repr_end = CPYTHON_DIFF[repr_start..]
        .find("\n// Differential smoke tests")
        .map(|offset| repr_start + offset)
        .expect("itertools repr diff subset must end before smoke tests");

    let core_helper_source = &CPYTHON_DIFF[core_helper_start..core_start];
    let core_source = &CPYTHON_DIFF[core_start..count_bool_start];
    let count_bool_source = &CPYTHON_DIFF[count_bool_start..keyword_start];
    let keyword_source = &CPYTHON_DIFF[keyword_start..pairwise_start];
    let pairwise_source = &CPYTHON_DIFF[pairwise_start..product_start];
    let product_source = &CPYTHON_DIFF[product_start..combinations_start];
    let combinations_source = &CPYTHON_DIFF[combinations_start..replacement_start];
    let replacement_source = &CPYTHON_DIFF[replacement_start..permutations_start];
    let permutations_source = &CPYTHON_DIFF[permutations_start..tee_start];
    let tee_source = &CPYTHON_DIFF[tee_start..batched_start];
    let batched_source = &CPYTHON_DIFF[batched_start..groupby_start];
    let groupby_source = &CPYTHON_DIFF[groupby_start..repr_start];
    let repr_source = &CPYTHON_DIFF[repr_start..repr_end];

    assert!(
        !core_source.contains("pairwise"),
        "itertools core CPython diff evidence must not cover pairwise()"
    );
    assert!(
        core_helper_source.contains("itertools.islice(range(3), None)"),
        "itertools core CPython diff helper evidence must cover islice(stop=None) two-argument behavior"
    );
    assert!(
        core_helper_source.contains("class BadIndex:")
            && core_helper_source.contains("itertools.islice(range(5), BadIndex())")
            && core_helper_source.contains("itertools.islice(range(5), BadIndex(), 3)")
            && core_helper_source.contains("itertools.islice(range(5), 1, 4, BadIndex())")
            && core_helper_source.contains("str(error)"),
        "itertools core CPython diff helper evidence must cover islice bad __index__ error classification"
    );
    for required in [
        "(True, False)",
        "(True, True)",
        "(False, True)",
        "(False, False)",
        "(True, 2)",
        "(1, True)",
    ] {
        assert!(
            count_bool_source.contains(required),
            "itertools count bool arithmetic CPython diff evidence must cover `{required}`"
        );
    }
    assert!(
        keyword_source.contains("itertools.count(foo=1)")
            && keyword_source.contains("itertools.count(1, start=2)")
            && keyword_source.contains("itertools.count(1, 2, step=3)")
            && keyword_source.contains("itertools.repeat(object=1, times=2, bad=3)")
            && keyword_source.contains("itertools.repeat(1, object=2)")
            && keyword_source.contains("itertools.repeat(1, 2, times=3)")
            && keyword_source.contains("itertools.compress()")
            && keyword_source.contains("itertools.compress([1], data=[])")
            && keyword_source.contains("itertools.groupby([1], iterable=[])")
            && keyword_source.contains("itertools.combinations([1], 1, r=2)")
            && keyword_source.contains("itertools.combinations_with_replacement([1], 1, r=2)")
            && keyword_source.contains("itertools.permutations([1], 1, r=2)")
            && keyword_source.contains("str(error)"),
        "itertools keyword-error CPython diff evidence must assert exact keyword diagnostics"
    );
    assert!(
        pairwise_source.contains("itertools.pairwise"),
        "itertools pairwise CPython diff evidence must cover pairwise()"
    );
    let pairwise_runtime_source =
        extract_rust_test_body(CPYTHON_SUBSET, "cpython_itertools_pairwise_subset");
    for required in [
        "pairwise expected 1 argument, got 0",
        "pairwise expected 1 argument, got 2",
    ] {
        assert!(
            pairwise_source.contains(required),
            "itertools pairwise CPython diff evidence must assert exact arity diagnostic `{required}`"
        );
        assert!(
            pairwise_runtime_source.contains(required),
            "itertools pairwise runtime evidence must assert exact arity diagnostic `{required}`"
        );
    }
    assert!(
        pairwise_source.contains("hasattr(itertools, 'pairwise')")
            && pairwise_source.contains("skipping itertools.pairwise diff"),
        "itertools pairwise CPython diff evidence must stay gated for older CPython oracles"
    );
    assert!(
        product_source.contains("itertools.product"),
        "itertools product CPython diff evidence must cover product()"
    );
    assert!(
        combinations_source.contains("itertools.combinations"),
        "itertools combinations CPython diff evidence must cover combinations()"
    );
    assert!(
        replacement_source.contains("itertools.combinations_with_replacement"),
        "itertools combinations_with_replacement CPython diff evidence must cover combinations_with_replacement()"
    );
    assert!(
        permutations_source.contains("itertools.permutations")
            && permutations_source.contains("itertools.permutations([1, 2], None)"),
        "itertools permutations CPython diff evidence must cover permutations() including r=None"
    );
    assert!(
        tee_source.contains("itertools.tee"),
        "itertools tee CPython diff evidence must cover tee()"
    );
    for required in [
        "c, d = itertools.tee(a)",
        "print(c is a, d is a, c is d)",
        "print(next(c), next(d), list(a), list(c), list(d), list(b))",
    ] {
        assert!(
            tee_source.contains(required),
            "itertools tee CPython diff evidence must cover tee-of-tee flattening `{required}`"
        );
    }
    assert!(
        batched_source.contains("itertools.batched"),
        "itertools batched CPython diff evidence must cover batched()"
    );
    assert!(
        groupby_source.contains("itertools.groupby"),
        "itertools groupby CPython diff evidence must cover groupby()"
    );
    assert!(
        repr_source.contains("repr("),
        "itertools repr CPython diff evidence must cover public repr() behavior"
    );
    for required in ["typ.__qualname__", "typ.__doc__", "values.append(group)"] {
        assert!(
            repr_source.contains(required),
            "itertools repr CPython diff evidence must cover public type metadata `{required}`"
        );
    }
}

#[test]
fn sandbox_stdlib_subset_without_same_named_diff_is_explicitly_classified() {
    let sandbox_prefixes = [
        "cpython_array_",
        "cpython_collections_",
        "cpython_copy_",
        "cpython_functools_",
        "cpython_io_",
        "cpython_itertools_",
        "cpython_json_",
        "cpython_operator_",
    ];

    let subset_names = rust_test_names(CPYTHON_SUBSET)
        .into_iter()
        .filter(|name| {
            sandbox_prefixes
                .iter()
                .any(|prefix| name.starts_with(prefix))
        })
        .filter_map(|name| name.strip_suffix("_subset").map(str::to_string))
        .collect::<BTreeSet<_>>();
    let diff_names = rust_test_names(CPYTHON_DIFF)
        .into_iter()
        .filter_map(|name| name.strip_suffix("_diff_subset").map(str::to_string))
        .collect::<BTreeSet<_>>();

    let missing_same_named_diff = subset_names
        .difference(&diff_names)
        .cloned()
        .collect::<BTreeSet<_>>();
    let expected = [
        "cpython_collections_chainmap_copy_pickle_eval_identity",
        "cpython_collections_counter_symmetric_difference_absent",
        "cpython_collections_namedtuple_pickle",
        "cpython_operator_pickle_helper",
    ]
    .into_iter()
    .map(str::to_string)
    .collect::<BTreeSet<_>>();
    assert_eq!(
        missing_same_named_diff, expected,
        "sandbox stdlib subset evidence without same-named CPython diff must be explicitly classified"
    );

    for subset in [
        "cpython_operator_pickle_helper_subset",
        "cpython_collections_chainmap_copy_pickle_eval_identity_subset",
        "cpython_collections_counter_symmetric_difference_absent_subset",
        "cpython_collections_namedtuple_pickle_subset",
    ] {
        assert!(
            CPYTHON_COVERAGE.contains(subset) && CPYTHON_MIGRATION.contains(subset),
            "pickle/eval identity subset `{subset}` must stay documented as subset-only support"
        );
    }
}

