#[test]
fn numeric_from_number_classmethod_metadata_subset_has_focused_diff_evidence() {
    for required in [
        "fn cpython_numeric_from_number_classmethod_metadata_subset(",
        "class F(float):",
        "class C(complex):",
        "float.from_number, float",
        "(1.0).from_number, float",
        "F.from_number, F",
        "complex.from_number, complex",
        "(1+1j).from_number, complex",
        "C.from_number, C",
        "method.__self__ is owner",
        "method.__text_signature__",
        "hasattr(method, '__func__')",
        "'__func__' in dir(method)",
        "method.__func__",
        "identity",
        "float.from_number(x=1)",
        "C.from_number(1, 2)",
        "(1+1j).from_number(x=1)",
    ] {
        assert!(
            CPYTHON_SUBSET.contains(required),
            "focused numeric from_number metadata subset evidence must cover `{required}`"
        );
    }

    let body = extract_rust_test_body(
        CPYTHON_DIFF,
        "cpython_numeric_from_number_classmethod_metadata_diff_subset",
    );
    for required in [
        "CPython float.from_number and complex.from_number classmethod metadata subset",
        "name: \"numeric-from-number-classmethod-metadata\"",
        "hasattr(float, 'from_number') and hasattr(complex, 'from_number')",
        "class F(float):",
        "class C(complex):",
        "method.__self__ is owner",
        "method.__text_signature__",
        "hasattr(method, '__func__')",
        "'__func__' in dir(method)",
        "method.__func__",
        "complex.from_number(cNAN) is cNAN",
        "C.from_number(x=1)",
    ] {
        assert!(
            body.contains(required),
            "focused numeric from_number metadata CPython diff evidence must cover `{required}`"
        );
    }

    for required in [
        "fn numeric_from_number_classmethod_value(",
        "fn numeric_from_number_builtin_owner(",
        "fn is_numeric_from_number_classmethod(",
        "fn numeric_from_number_owner_name(",
        "numeric_from_number_classmethod_value(\"float\")",
        "numeric_from_number_classmethod_value(\"complex\")",
        "'builtin_function_or_method' object has no attribute '__func__'",
        "is_numeric_from_number_classmethod(name)",
        "float.from_number() takes exactly one argument",
        "complex.from_number() takes exactly one argument",
        "matches!(class, Value::Builtin(name) if name == \"complex\")",
    ] {
        assert!(
            VM_SOURCE.contains(required),
            "numeric from_number metadata implementation must contain `{required}`"
        );
    }

    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        assert!(
            document.contains("cpython_numeric_from_number_classmethod_metadata_subset")
                && document
                    .contains("cpython_numeric_from_number_classmethod_metadata_diff_subset")
                && document.contains("from_number` classmethod metadata")
                && document.contains("absence of `__func__`"),
            "focused numeric from_number metadata evidence must be documented in coverage and migration notes"
        );
    }
}

#[test]
fn collections_deque_attribute_assignment_errors_subset_has_focused_diff_evidence() {
    let subset_body = extract_rust_test_body(
        CPYTHON_SUBSET,
        "cpython_collections_deque_attribute_assignment_errors_subset",
    );
    for required in [
        "d = deque([1, 2], maxlen=3)",
        "setattr(d, name, 99)",
        "delattr(d, name)",
        "['extra', 'maxlen', 'append', 'clear']",
        "\"set-extra AttributeError 'collections.deque' object has no attribute 'extra' and no __dict__ for setting new attributes\"",
        "\"set-maxlen AttributeError attribute 'maxlen' of 'collections.deque' objects is not writable\"",
        "\"set-append AttributeError 'collections.deque' object attribute 'append' is read-only\"",
        "\"del-clear AttributeError 'collections.deque' object attribute 'clear' is read-only\"",
        "\"read deque 3 [1, 2]\"",
    ] {
        assert!(
            subset_body.contains(required),
            "collections deque attribute assignment subset evidence must cover `{required}`"
        );
    }

    let diff_body = extract_rust_test_body(
        CPYTHON_DIFF,
        "cpython_collections_deque_attribute_assignment_errors_diff_subset",
    );
    for required in [
        "Lib/test/test_collections.py deque public instance attribute assignment errors subset",
        "name: \"collections-deque-attribute-assignment-errors\"",
        "d = deque([1, 2], maxlen=3)",
        "setattr(d, name, 99)",
        "delattr(d, name)",
        "['extra', 'maxlen', 'append', 'clear']",
        "type(d).__name__",
        "list(d)",
    ] {
        assert!(
            diff_body.contains(required),
            "collections deque attribute assignment CPython diff evidence must cover `{required}`"
        );
    }

    for required in [
        "Value::Deque { .. } => Err(deque_attribute_assignment_error(name))",
        "fn deque_attribute_assignment_error(name: &str) -> String",
        "fn is_deque_readonly_instance_attribute(name: &str) -> bool",
        "builtin_type_dir_names(\"deque\")",
        "attribute 'maxlen' of 'collections.deque' objects is not writable",
        "'collections.deque' object attribute '{name}' is read-only",
        "'collections.deque' object has no attribute",
        "no __dict__ for setting new attributes",
    ] {
        assert!(
            VM_SOURCE.contains(required),
            "collections deque attribute assignment implementation must contain `{required}`"
        );
    }

    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        assert!(
            document.contains("cpython_collections_deque_attribute_assignment_errors_subset")
                && document
                    .contains("cpython_collections_deque_attribute_assignment_errors_diff_subset")
                && document.contains("deque attribute assignment errors")
                && document.contains("read-only deque data attributes")
                && document.contains("read-only deque method attributes")
                && document.contains("without adding deque instance dictionaries"),
            "collections deque attribute assignment evidence must be documented in coverage and migration notes"
        );
    }
}

