#[test]
fn types_functiontype_unacceptable_base_type_docs_cover_core_runtime() {
    let diff_name = "cpython_types_functiontype_unacceptable_base_type_diff_subset";
    let subset_name = "cpython_types_functiontype_unacceptable_base_type_subset";

    assert!(
        CPYTHON_DIFF.contains(&format!("fn {diff_name}(")),
        "types FunctionType unacceptable-base CPython diff evidence must exist"
    );
    assert!(
        CPYTHON_SUBSET.contains(&format!("fn {subset_name}(")),
        "types FunctionType unacceptable-base runtime subset evidence must exist"
    );

    for required in [
        "base = types.FunctionType",
        "class FunctionClass(base):",
        "type('FunctionTypeClass', (types.FunctionType,), {})",
        "type.__new__(type, 'FunctionTypeNew', (types.FunctionType,), {})",
        "types.new_class('FunctionTypeNewClass', (types.FunctionType,), {})",
        "type('RuntimeFunctionClass', (f.__class__,), {})",
        "class ModuleClass(types.ModuleType):",
        "type 'function' is not an acceptable base type",
        "error.args",
    ] {
        assert!(
            CPYTHON_DIFF.contains(required) && CPYTHON_SUBSET.contains(required),
            "types FunctionType unacceptable-base diff and subset evidence must both cover `{required}`"
        );
    }

    for required in [
        "\"class-functiontype TypeError type 'function' is not an acceptable base type",
        "\"type-functiontype TypeError type 'function' is not an acceptable base type",
        "\"type-new-functiontype TypeError type 'function' is not an acceptable base type",
        "\"new-class-functiontype TypeError type 'function' is not an acceptable base type",
        "\"class-function-runtime TypeError type 'function' is not an acceptable base type",
        "\"module-control ModuleClass True\"",
    ] {
        assert!(
            CPYTHON_SUBSET.contains(required),
            "types FunctionType unacceptable-base subset output must pin `{required}`"
        );
    }

    let class_base_body = VM_SOURCE
        .split("fn is_class_base_builtin_type(name: &str) -> bool")
        .nth(1)
        .and_then(|tail| tail.split("fn base_needs_original_bases").next())
        .expect("is_class_base_builtin_type implementation must be extractable");
    assert!(
        class_base_body.contains("\"function\""),
        "FunctionType must be recognized as a class-base candidate before final validation"
    );

    let final_type_body = VM_SOURCE
        .split("fn is_final_builtin_type(name: &str) -> bool")
        .nth(1)
        .and_then(|tail| tail.split("fn builtin_has_instance_layout").next())
        .expect("is_final_builtin_type implementation must be extractable");
    assert!(
        final_type_body.contains("\"function\""),
        "FunctionType must be classified as a non-subclassable builtin type"
    );

    for required in [
        "fn validate_type_constructor_bases(",
        "is_class_base_builtin_type(&name)",
        "type '{public_name}' is not an acceptable base type",
        "validate_type_constructor_bases(&normalized_bases)?",
        "validate_type_constructor_bases(&bases)?",
    ] {
        assert!(
            VM_SOURCE.contains(required),
            "types FunctionType unacceptable-base implementation must contain `{required}`"
        );
    }

    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        for required in [
            diff_name,
            subset_name,
            "types.FunctionType",
            "type 'function' is not an acceptable base type",
            "class statements",
            "`type(...)`",
            "`type.__new__(...)`",
            "`types.new_class(...)`",
            "runtime function",
            "ModuleType",
        ] {
            assert!(
                document.contains(required),
                "types FunctionType unacceptable-base docs must contain `{required}`"
            );
        }
    }
}

